const getData = () => {
if (state.searchInfo.timeValue && global.regionaQuery.regionType === 'region') {
  // 整体考核评价
  apiRegistry.getPJResultInfo.request();
  // 整体考核评价-断面总数
  apiRegistry.getKHPJTotals.request();
  // 优良率/劣Ⅴ类考核目标值
  apiRegistry.getKHMBNum.request();
  // 区域考核结果列表-行政区
  apiRegistry.getKHResultList.request();
} else if (state.searchInfo.timeValue && global.regionaQuery.regionType === 'wsystem') {
  // 整体考核评价
  apiRegistry.getPJResultInfo.request();
  // 整体考核评价-断面总数
  apiRegistry.getKHPJTotals.request();
  // 优良率/劣Ⅴ类考核目标值
  apiRegistry.getKHMBNum.request();
  // 区域考核结果列表-流域
  apiRegistry.getKHResultListLY.request();
}
};
const gotoMapLocationLY = (row,column) => {
// 点击定位给地图发消息
if (["定位", '流域', '优良率', '劣Ⅴ类占比', '达标率'].includes(column.label)) {
  // 注意 这时候 还修改了 左上角选中区域值(估计是 发消息时 区域选择也接收了)
  rootData.rootSocket.emit('message', {
    room: global.socketRoom,// 房间号
    type: "runInteractive", // 消息名称
    // 消息内容
    "data": [
      {
        "code": "wsystem_name",
        "shareCode": "WSYSTEM_NAME",
        "defaultValue": "",
        "runtimeValue": row.WSYSTEM_NAME
      },
      {
        "code": "wsystem_code",
        "name": "",
        "defaultValue": "",
        "shareCode": "WSYSTEM_CODE",
        "runtimeValue": row.WSYSTEM_CODE
      }
    ]
  });
}


};
